const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const site = data.site || 'UNKNOWN';
  const keyword = data.keyword || 'UNKNOWN';
  const status = data.status;
  const product = data.item;

  let msg = `[${site.toUpperCase()}] Từ khoá: <b>${keyword}</b>\n`;
  const title = product.productName || product.title || 'No Title';
  const url = product.productURL || product.url || '';

  if (status.type === 'new') {
    msg += `🆕 <b>Sản phẩm mới!</b>\n`;
    msg += `Tên: <a href="${url}">${title}</a>\n`;
    msg += `Giá: ${product.price || product.curr_price}\n`;
  } else if (status.type === 'modified') {
    msg += `⚠️ <b>Cập nhật sản phẩm!</b>\n`;
    msg += `Tên: <a href="${url}">${title}</a>\n`;
    if (status.changes && status.changes.price) {
      msg += `💰 Giá: <s>${status.changes.price.old}</s> ➡️ ${status.changes.price.new}\n`;
    }
    if (status.changes && status.changes.status) {
      msg += `Trạng thái: <s>${status.changes.status.old}</s> ➡️ ${status.changes.status.new}\n`;
    }
  } else if (status.type === 'ending_soon') {
    msg += `⏰ <b>Sắp kết thúc phiên! (Còn 30p - 1h)</b>\n`;
    msg += `Tên: <a href="${url}">${title}</a>\n`;
    msg += `Giá: ${product.price || product.curr_price}\n`;
  }

  if (status.ending_soon) {
    msg += `⏰ <b>Sắp kết thúc phiên! (Còn 30p - 1h)</b>\n`;
  }

  const itemId = product.id_ || product.item_id || product.id || url.split('/').pop();
  if (itemId) {
    msg += `\n🚫 Bỏ qua SP này: /exclude_${itemId}\n`;
  }

  results.push({ json: { telegram_text: msg } });
}

return results;
